mapper.select:
select max(last_time)
from patient_raw_data
where reqno = #{reqno}

WITH candidate_reqnos AS (
    SELECT
        pat.reqno,
        pat.inhosdate AS sort_time
    FROM pat_infor pat
    WHERE pat.reqno IS NOT NULL
      AND pat.inhosdate >= DATEADD(DAY, -#{recentAdmissionDays}, GETDATE())
      AND NOT EXISTS (
        SELECT 1
        FROM patient_raw_data prd
        WHERE prd.reqno = pat.reqno
      )

        UNION ALL
        SELECT updated.reqno, MAX(updated.lasttime) AS sort_time
        FROM (
            SELECT reqno, lasttime FROM patdiaginfor WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM PatBodySurface WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patdoctoradvice WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patillnesscourse WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM pattestsam WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM pattestresult WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patusemedicine WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patvideoresult WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM PatDeptChange WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patopscutinfor WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patusemedicine_ops WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM pattest WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patmicrobesource_rep WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patmicrobesource WHERE lasttime > #{sinceTime}
            UNION ALL
            SELECT reqno, lasttime FROM patantisource WHERE lasttime > #{sinceTime}
        ) updated
        WHERE updated.reqno IS NOT NULL
          AND EXISTS (
            SELECT 1
            FROM patient_raw_data prd
            WHERE prd.reqno = updated.reqno
          )
        GROUP BY updated.reqno

)
SELECT reqno
FROM (
    SELECT reqno, MAX(sort_time) AS latest_time
    FROM candidate_reqnos
    GROUP BY reqno
) final_candidates
where reqno = '260300011'
ORDER BY latest_time ASC
OFFSET 0 ROWS FETCH NEXT #{limit} ROWS ONLY

choose.otherwise:
SELECT DISTINCT source_type
FROM (
    SELECT 'DIAGNOSIS' AS source_type FROM patdiaginfor WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'BODY_SURFACE' AS source_type FROM PatBodySurface WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'DOCTOR_ADVICE' AS source_type FROM patdoctoradvice WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'ILLNESS_COURSE' AS source_type FROM patillnesscourse WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'LAB_TEST' AS source_type FROM pattestsam WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'LAB_TEST' AS source_type FROM pattestresult WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'USE_MEDICINE' AS source_type FROM patusemedicine WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'VIDEO_RESULT' AS source_type FROM patvideoresult WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'TRANSFER' AS source_type FROM PatDeptChange WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'OPERATION' AS source_type FROM patopscutinfor WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'OPERATION' AS source_type FROM patusemedicine_ops WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'MICROBE' AS source_type FROM pattest WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'MICROBE' AS source_type FROM patmicrobesource_rep WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'MICROBE' AS source_type FROM patmicrobesource WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
    UNION ALL
    SELECT 'MICROBE' AS source_type FROM patantisource WHERE reqno = #{reqno} AND lasttime > #{sinceTime}
) changed

mapper.select:
select a.diag_id, a.reqno, a.phase, a.diag_name, a.diag_time from patdiaginfor a inner join pat_infor p on a.reqno = p.reqno inner join district_dict d on p.currentdist = d.datano where a.reqno = #{reqno}
and a.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
) order by a.diag_time

SELECT pbs.reqno, pbs.measuredate, pbs.flag, MAX(CASE WHEN pbs.flag = '体温' THEN pbs.temperature END) AS temperature, MAX(CASE WHEN pbs.flag = '大便次数' THEN pbs.temperature END) AS stool_count, MAX(CASE WHEN pbs.flag = '脉搏' THEN pbs.temperature END) AS pulse, MAX(CASE WHEN pbs.flag = '呼吸' THEN pbs.temperature END) AS breath, MAX(CASE WHEN pbs.flag = '血压' AND pbs.temperature = -1 THEN pbs.strval WHEN pbs.flag = '血压' AND pbs.temperature <> -1 THEN CAST(pbs.temperature AS VARCHAR) END) AS blood_pressure FROM PatBodySurface pbs where reqno = #{reqno}
and pbs.lasttime > #{lastTime}
GROUP BY pbs.reqno, pbs.measuredate, pbs.flag

SELECT p.docadvno, p.reqno, p.docadvice, --医嘱名称 p.begtime, --开始时间 CASE WHEN CONVERT(VARCHAR(10), p.endtime, 120) IN ('9999-12-31', '1900-01-01') THEN '未结束' ELSE CONVERT(VARCHAR(19), p.endtime, 120) END AS endtime, --结束时间 p.docadvtype, --医嘱类型 p.memo AS remarks, --备注 d.data_name as distname FROM patdoctoradvice p inner join district_dict d on p.distno=d.datano WHERE docadvtype = '长期' AND reqno = #{reqno} AND (COALESCE('_', '_') = '_' OR docadvice LIKE '%' + '_' + '%')
and lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
ORDER BY begtime DESC

SELECT p.docadvno, p.reqno, docadvice, begtime, CASE WHEN CONVERT(VARCHAR(10), endtime, 120) IN ('9999-12-31', '1900-01-01') THEN '未结束' ELSE CONVERT(VARCHAR(19), endtime, 120) END AS endtime, docadvtype, memo AS remarks, d.data_name as distname FROM patdoctoradvice p inner join district_dict d on p.distno=d.datano WHERE (COALESCE('临时', '_') = '_' OR docadvtype = '临时') AND reqno = #{reqno} AND (COALESCE('_', '_') = '_' OR docadvice LIKE '%' + '_' + '%')
and lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
ORDER BY begtime DESC

SELECT p.docadvno, p.reqno, docadvice, begtime, CASE WHEN CONVERT(VARCHAR(10), endtime, 120) IN ('9999-12-31', '1900-01-01') THEN '未结束' ELSE CONVERT(VARCHAR(19), endtime, 120) END AS endtime, docadvtype, memo AS remarks, d.data_name as distname FROM patdoctoradvice p inner join district_dict d on p.distno=d.datano WHERE (COALESCE('_', '_') = '_' OR docadvtype = '_') AND reqno = #{reqno} AND (COALESCE('_', '_') = '_' OR docadvice LIKE '%' + '_' + '%') AND sg_flag IS NOT NULL
and lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
ORDER BY begtime DESC

SELECT i.id, i.reqno, i.illnesscontent, i.creattime, --创建时间 i.changetime, --创建时间 i.itemname FROM patillnesscourse i inner join pat_infor p on i.reqno=p.reqno inner join district_dict d on p.currentdist=d.datano WHERE 1 = 1 AND i.reqno = #{reqno} and(COALESCE(NULLIF('', '_'), '') = '' OR i.id = '')
and i.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)

select reqno, samreqno, sendtestdate, testaim, samtype data_name, testdate from pattestsam pt inner join district_dict d on pt.distno=d.datano where reqno=#{reqno}
and pt.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
order by sendtestdate desc

select pt.reqno, pt.samreqno, pm.itemno, pm.itemname, engname, resultdesc, state, unit, refdesc, CASE WHEN pm.state <> '正常' THEN '异常' ELSE '正常' END AS all_jy_flag from pattestsam pt inner join pattestresult pm on pt.reqno=pm.reqno and pt.samreqno=pm.samreqno inner join district_dict d on pt.distno=d.datano where 1=1 and pt.reqno=#{reqno} and pt.samreqno=#{samreqno}
and pt.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)

SELECT reqno, useorderno, medi_id, medi_name, med_calss, medi_path, begin_time, convert(varchar(19),zxsj,120) as zxsj, CASE WHEN CONVERT(VARCHAR(10), end_time, 120) IN ('9999-12-31', '1900-01-01') THEN '未结束' ELSE CONVERT(VARCHAR(19), end_time, 120) END AS end_time, medi_aim, docadvtype, dosage AS medi_num, medusage, frequency, unit, memo, d.data_name as distname FROM patusemedicine p inner join district_dict d on p.distno=d.datano WHERE 1 = 1 AND docadvtype = '长期' AND reqno = #{reqno}
and lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
ORDER BY begin_time DESC

SELECT pd.reqno, pd.samreqno, pd.itemno, pd.docadvtime, CONVERT(VARCHAR, docadvtime, 120) + itemname AS names, pd.diagnose, testresult, reporttime FROM patvideoresult pd inner join pat_infor p on pd.reqno=p.reqno inner join district_dict d on p.currentdist=d.datano WHERE 1 = 1 AND pd.reqno = #{reqno} and(COALESCE(NULLIF('', '_'), '') = '' OR CONVERT(VARCHAR, reporttime, 112) = '') and(COALESCE(NULLIF('', '_'), '') = '' OR pd.samreqno = '')
and lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
ORDER BY reporttime

SELECT ops.reqno, ops.ops_id, ops.ops_name, ops.beg_time, CASE WHEN CONVERT(VARCHAR(10), ops.end_time, 120) IN ('9999-12-31', '1900-01-01') THEN '未结束' ELSE CONVERT(VARCHAR(19), ops.end_time, 120) END AS end_time, ops.cut_type, hocus_mode FROM patopscutinfor ops inner join district_dict d on ops.opsdept=d.datano WHERE 1 = 1 AND ops.pathosid IN (SELECT pathosid FROM pat_infor WHERE reqno = #{reqno}) AND DATEDIFF(DAY, ops.beg_time, CURRENT_TIMESTAMP) <= 365
and ops.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)

select ops.reqno, ops.ops_id, med.useorderno, med.medi_id, med.medi_name, med.dosage + med.unit as dosage, med.begin_time from patopscutinfor ops inner join patusemedicine med on ops.reqno=med.reqno inner join district_dict d on ops.opsdept=d.datano where ops.reqno=#{reqno} and ops.ops_id= #{opsId}
and med.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)

select ops.reqno, ops.ops_id, med.useorderno, med.medi_id, med.medi_name, med.dosage + med.unit as dosage, med.begin_time from patopscutinfor ops inner join patusemedicine_ops med on ops.reqno=med.reqno and ops.ops_id=med.ops_id inner join district_dict d on ops.opsdept=d.datano where ops.reqno=#{reqno} and ops.ops_id= #{opsId}
and med.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)

select pte.reqno, pte.testobject, pte.samreqno, pte.sampletime, pte.samtype_name as data_name from pattest pte left join patmicrobesource ps on pte.reqno = ps.reqno AND pte.samreqno = ps.samreqno left join district_dict d on pte.dist=d.datano where 1=1 and pte.reqno=#{reqno}
and pte.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
)
order by sampletime desc

select * from ( SELECT pt.reqno, pt.samreqno, pt.sampletime AS sendtestdate, pt.samtype_name AS samtypename, pt.samtype_name AS samtype, pm.exedate, pm.data_code, CASE WHEN ps.reqno IS NOT NULL AND pm.reqno IS NOT NULL THEN '阳性' ELSE '阴性' END AS result ,case when ps.reqno IS not null and ps.memo is not null then '多重耐药' end AS result1 ,case when ps.reqno IS null and pm.memo is not null then '细菌备注' end AS result2 FROM pattest pt INNER JOIN patmicrobesource_rep pm ON pt.reqno = pm.reqno AND pt.samreqno = pm.samreqno LEFT JOIN ( SELECT reqno, samreqno,data_code,memo FROM patmicrobesource WHERE reqno = #{reqno} GROUP BY reqno, samreqno,data_code,memo ) AS ps ON pt.reqno = ps.reqno AND pt.samreqno = ps.samreqno and pm.data_code=ps.data_code left join ( select reqno,samreqno,microbecode,count(*) as nys from patantisource where 1=1 and reqno=#{reqno} and(COALESCE(NULLIF(#{samreqno}, '_'), '') = '' OR samreqno = #{samreqno}) and(COALESCE(NULLIF('', '_'), '') = '' OR microbecode = '') GROUP BY reqno,samreqno,microbecode ) AS pts ON pt.reqno = pts.reqno AND pt.samreqno = pts.samreqno and pts.microbecode=ps.data_code
LEFT JOIN district_dict d ON pt.dist = d.datano LEFT JOIN pat_infor pat ON pat.reqno = pt.reqno WHERE 1 = 1 AND pt.reqno = #{reqno} AND ( (COALESCE(NULLIF(#{samreqno}, '_'), '') = '' AND ps.reqno IS NOT NULL AND pm.reqno IS NOT NULL) OR (COALESCE(NULLIF(#{samreqno}, '_'), '') != '' AND pm.samreqno = #{samreqno}) )
and pm.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
) ) t2 ORDER BY sendtestdate DESC

select a.reqno, a.samreqno, a.microbecode, a.micresult mic, a.datano, a.data_name, a.micexplain sensitivity from patantisource a inner join pat_infor p on a.reqno=p.reqno inner join district_dict d on p.currentdist=d.datano left join main_antiitem c on a.datano=c.datano where 1=1 and a.reqno=#{reqno} and(COALESCE(NULLIF(#{samreqno}, '_'), '') = '' OR a.samreqno = #{samreqno}) and(COALESCE(NULLIF(#{dataCode}, '_'), '') = '' OR a.microbecode = #{dataCode})
and a.lasttime > #{lastTime}
and ( coalesce('0','0')='0' or (coalesce('0','0')='1' and (coalesce(d.depcss,'_')='本院' or coalesce('本院','_')='_'))
) order by item_memo1 DESC
